## 1. `/Users/duhl/git/ui/apps/org-next/src/routes/_authed.tsx`

```1:49:/Users/duhl/git/ui/apps/org-next/src/routes/_authed.tsx
import { createFileRoute, Outlet, redirect } from "@tanstack/react-router";
import { createServerFn } from "@tanstack/react-start";

const loadAuthedRouteFn = createServerFn({ method: "GET" }).handler(
  async () => {
    const { getAppBootstrapData } = await import("../server/app-bootstrap");
    const { OrgApiError } = await import("../server/error");

    try {
      const appBootstrap = await getAppBootstrapData();

      if (!appBootstrap) {
        throw redirect({ to: "/login" });
      }

      return appBootstrap;
    } catch (error) {
      if (error instanceof OrgApiError && error.status === 401) {
        throw redirect({ to: "/login" });
      }

      throw error;
    }
  },
);

export const Route = createFileRoute("/_authed")({
  loader: async ({ location }) => {
    const appBootstrap = await loadAuthedRouteFn();
    if (!appBootstrap) {
      throw redirect({ to: "/login" });
    }

    const onWorkspaceNewRoute =
      location.pathname === "/workspace/new" ||
      location.pathname.endsWith("/workspace/new");

    if (appBootstrap.user && !appBootstrap.tenant && !onWorkspaceNewRoute) {
      throw redirect({ to: "/workspace/new" });
    }

    return appBootstrap;
  },
  component: AuthedLayout,
});

function AuthedLayout() {
  return <Outlet />;
}
```

**Behavior:** `GET` server function loads `getAppBootstrapData()`; missing bootstrap or `OrgApiError` with status 401 → redirect to `/login`. Loader repeats the null check, then if there is a user without a tenant and the path is not `/workspace/new`, redirects to `/workspace/new`. Layout is only `<Outlet />`.

