## 3. `/Users/duhl/git/ui/apps/org-next/src/router.tsx`

```1:33:/Users/duhl/git/ui/apps/org-next/src/router.tsx
import { QueryClient } from "@tanstack/react-query";
import { createRouter } from "@tanstack/react-router";
import { setupRouterSsrQueryIntegration } from "@tanstack/react-router-ssr-query";
import { routeTree } from "./routeTree.gen";

const enableRequestMocking = import.meta.env.VITE_ENABLE_RMP === "true";

if (enableRequestMocking && import.meta.env.SSR) {
  const { setupRequestMocking } = await import("./mocks/request-mocking");
  setupRequestMocking();
}

export const getRouter = () => {
  const rqContext = {
    queryClient: new QueryClient(),
  };

  const router = createRouter({
    context: {
      ...rqContext,
    },
    defaultPreload: "intent",
    routeTree,
  });

  setupRouterSsrQueryIntegration({
    queryClient: rqContext.queryClient,
    router,
  });

  return router;
};
```

**Behavior:** New `QueryClient` per `getRouter()` call, `setupRouterSsrQueryIntegration` links router and React Query for SSR.

